class Solution {
    bool helper(string& s,int l,int r,bool used){
        while(l<r){
            if(s[l]!=s[r]){
                if(used) return false;
                return helper(s,l+1,r,true)||helper(s,l,r-1,true);
            }
            l++; r--;
        }
        return true;
    }
public:
    bool validPalindrome(string s){ return helper(s,0,s.size()-1,false); }
};
